class Solution:
    def search(self, nums: list[int], target: int, low: int, high: int) -> bool:
        if low > high:
            return False
        mid = (low + high) // 2
        if nums[mid] == target:
            return True
        if nums[low] <= nums[mid]:
            if nums[low] <= target < nums[mid]:
                high = mid - 1
            else:
                low = mid + 1
        else:
            if nums[mid] < target <= nums[high]:
                low = mid + 1
            else:
                high = mid - 1
        return self.search(nums, target, low, high)


